content:
{
  "sentences": [
    {
      "text": "師傅，請問你什麼時候可以過來看看？",
      "pinyin": "Shīfu, qǐngwèn nǐ shénme shíhou kěyǐ guòlái kànkan?",
      "pinyin_numeric": "shi1fu0, qing3wen4 ni3 shen2me shi2hou0 ke3yi3 guo4lai2 kan4kan0",
      "translation_en": "Master, may I ask when you can come over to take a look?",
      "translation_ko": "사장님, 언제 오셔서 확인해 주실 수 있나요?"
    },
    {
      "text": "我什麼時候可以請你來修理馬桶？",
      "pinyin": "Wǒ shénme shíhou kěyǐ qǐng nǐ lái xiūlǐ mǎtǒng?",
      "pinyin_numeric": "wo3 shen2me shi2hou0 ke3yi3 qing3 ni3 lai2 xiu1li3 ma3tong3",
      "translation_en": "When can I ask you to come repair the toilet?",
      "translation_ko": "언제 변기 수리를 부탁드릴 수 있을까요?"
    },
    {
      "text": "水龍頭壞掉了，你什麼時候可以來換？",
      "pinyin": "Shuǐlóngtóu huài diào le, nǐ shénme shíhou kěyǐ lái huàn?",
      "pinyin_numeric": "shui3long2tou2 huai4 diao4 le0, ni3 shen2me shi2hou0 ke3yi3 lai2 huan4",
      "translation_en": "The faucet is broken; when can you come to replace it?",
      "translation_ko": "수도꼭지가 고장 났는데, 언제 오셔서 교체해 주실 수 있나요?"
    },
    {
      "text": "我什麼時候可以預約時間請你檢查冷氣？",
      "pinyin": "Wǒ shénme shíhou kěyǐ yùyuē shíjiān qǐng nǐ jiǎnchá lěngqì?",
      "pinyin_numeric": "wo3 shen2me shi2hou0 ke3yi3 yu4yue1 shi2jian1 qing3 ni3 jian3cha2 leng3qi4",
      "translation_en": "When can I schedule a time for you to check the air conditioner?",
      "translation_ko": "언제 에어컨 점검을 예약할 수 있을까요?"
    },
    {
      "text": "熱水器有奇怪的聲音，你什麼時候可以過來看看？",
      "pinyin": "Rèshuǐqì yǒu qíguài de shēngyīn, nǐ shénme shíhou kěyǐ guòlái kànkan?",
      "pinyin_numeric": "re4shui3qi4 you3 qi2guai4 de0 sheng1yin1, ni3 shen2me shi2hou0 ke3yi3 guo4lai2 kan4kan0",
      "translation_en": "The water heater is making a strange noise; when can you come over to take a look?",
      "translation_ko": "온수기에서 이상한 소리가 나는데, 언제 오셔서 확인해 주실 수 있나요?"
    },
    {
      "text": "冰箱不冷了，你什麼時候可以來修理？",
      "pinyin": "Bīngxiāng bù lěng le, nǐ shénme shíhou kěyǐ lái xiūlǐ?",
      "pinyin_numeric": "bing1xiang1 bu4 leng3 le0, ni3 shen2me shi2hou0 ke3yi3 lai2 xiu1li3",
      "translation_en": "The refrigerator is not cold anymore; when can you come to repair it?",
      "translation_ko": "냉장고가 차갑지 않은데, 언제 수리하러 오실 수 있나요?"
    },
    {
      "text": "我什麼時候可以請你來處理牆壁的裂縫？",
      "pinyin": "Wǒ shénme shíhou kěyǐ qǐng nǐ lái chǔlǐ qiángbì de lièfèng?",
      "pinyin_numeric": "wo3 shen2me shi2hou0 ke3yi3 qing3 ni3 lai2 chu3li3 qiang2bi4 de0 lie4feng4",
      "translation_en": "When can I ask you to come deal with the crack in the wall?",
      "translation_ko": "언제 벽에 금 간 것을 처리해 주실 수 있나요?"
    },
    {
      "text": "排水堵住了，你什麼時候可以過來看看？",
      "pinyin": "Páishuǐ dǔ zhù le, nǐ shénme shíhou kěyǐ guòlái kànkan?",
      "pinyin_numeric": "pai2shui3 du3 zhu4 le0, ni3 shen2me shi2hou0 ke3yi3 guo4lai2 kan4kan0",
      "translation_en": "The drain is clogged; when can you come over to take a look?",
      "translation_ko": "배수가 막혔는데, 언제 오셔서 확인해 주실 수 있나요?"
    },
    {
      "text": "門鎖壞掉了，你什麼時候可以來換一個新的？",
      "pinyin": "Mén suǒ huài diào le, nǐ shénme shíhou kěyǐ lái huàn yī ge xīn de?",
      "pinyin_numeric": "men2 suo3 huai4 diao4 le0, ni3 shen2me shi2hou0 ke3yi3 lai2 huan4 yi1 ge0 xin1 de0",
      "translation_en": "The door lock is broken; when can you come to replace it with a new one?",
      "translation_ko": "문 잠금장치가 고장 났는데, 언제 새것으로 교체하러 오실 수 있나요?"
    },
    {
      "text": "我什麼時候可以請你來修理洗衣機？",
      "pinyin": "Wǒ shénme shíhou kěyǐ qǐng nǐ lái xiūlǐ xǐyījī?",
      "pinyin_numeric": "wo3 shen2me shi2hou0 ke3yi3 qing3 ni3 lai2 xiu1li3 xi3yi1ji1",
      "translation_en": "When can I ask you to come repair the washing machine?",
      "translation_ko": "언제 세탁기 수리를 부탁드릴 수 있을까요?"
    }
  ]
}
